import React, { useState, useEffect } from 'react';
import { Button, Text, View } from 'react-native';
import axios from 'axios';

const OAuth2App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  const config = {
    clientId: 'YOUR_CLIENT_ID',
    clientSecret: 'YOUR_CLIENT_SECRET',
    authUrl: 'https://your-oauth-server.com/auth',
    tokenUrl: 'https://your-oauth-server.com/token',
    redirectUri: 'your-app-scheme://callback'
  };

  useEffect(() => {
    if (accessToken) {
      // Schedule a token refresh before the token expires
      const timer = setTimeout(refreshTokenFunction, 3600000); // Refresh after 1 hour
      return () => clearTimeout(timer);
    }
  }, [accessToken]);

  const authorize = async () => {
    try {
      const authUrl = `${config.authUrl}?response_type=code&client_id=${config.clientId}&redirect_uri=${encodeURIComponent(config.redirectUri)}`;
      Linking.openURL(authUrl);
    } catch (error) {
      console.error('Authorization failed:', error);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await axios.post(config.tokenUrl, {
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: config.redirectUri,
        client_id: config.clientId,
        client_secret: config.clientSecret
      });

      setAccessToken(response.data.access_token);
      setRefreshToken(response.data.refresh_token);
    } catch (error) {
      console.error('Token exchange failed:', error);
    }
  };

  const refreshTokenFunction = async () => {
    try {
      const response = await axios.post(config.tokenUrl, {
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
        client_id: config.clientId,
        client_secret: config.clientSecret
      });

      setAccessToken(response.data.access_token);
    } catch (error) {
      console.error('Token refresh failed:', error);
    }
  };

  return (
    <View>
      {accessToken ? (
        <Text>Access Token: {accessToken}</Text>
      ) : (
        <Button title="Authorize" onPress={authorize} />
      )}
    </View>
  );
};

export default OAuth2App;